// Some portions generated by Claude
package org.eclipse.rdf4j.query.algebra.equivalence.internal;

import java.util.ArrayList;
import java.util.List;
import java.util.Optional;

import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.equivalence.AlgebraEquivalenceChecker;
import org.eclipse.rdf4j.query.algebra.equivalence.CheckOptions;
import org.eclipse.rdf4j.query.algebra.equivalence.Counterexample;
import org.eclipse.rdf4j.query.algebra.equivalence.EquivalenceResult;
import org.eclipse.rdf4j.query.algebra.equivalence.EquivalenceStatus;
import org.eclipse.rdf4j.query.algebra.equivalence.EvaluationCase;
import org.eclipse.rdf4j.query.algebra.equivalence.EvaluationOutcome;

/**
 * The asymmetric differential oracle: evaluation can refute equivalence but never confirm it. An {@code EQUIVALENT}
 * verdict is attacked with the checker's own {@link BoundedCounterexampleFinder} (mandatory, because {@code check()}
 * short-circuits on the proof path before consulting any evaluation case); a {@code NOT_EQUIVALENT} verdict must carry
 * a witness that replays stably; {@code UNKNOWN} is never punished.
 */
final class DifferentialOracle {

	List<FuzzViolation> judge(TreePair pair, FuzzProfile profile) {
		List<FuzzViolation> violations = new ArrayList<>();
		CheckOptions options = profile.options();

		EquivalenceResult first;
		try {
			first = new AlgebraEquivalenceChecker(options).check(pair.original(), pair.candidate());
		} catch (Throwable t) {
			violations.add(new FuzzViolation(FuzzInvariant.ROBUSTNESS, profile.label(), pair,
					"check() threw " + t.getClass().getSimpleName() + ": " + t.getMessage()));
			return violations;
		}

		try {
			EquivalenceResult repeat = new AlgebraEquivalenceChecker(options).check(pair.original(), pair.candidate());
			if (repeat.getStatus() != first.getStatus()) {
				violations.add(new FuzzViolation(FuzzInvariant.DETERMINISM, profile.label(), pair,
						"repeat check flipped " + first.getStatus() + " -> " + repeat.getStatus()));
			}
			EquivalenceResult swapped = new AlgebraEquivalenceChecker(options).check(pair.candidate(), pair.original());
			boolean conflict = (first.getStatus() == EquivalenceStatus.EQUIVALENT
					&& swapped.getStatus() == EquivalenceStatus.NOT_EQUIVALENT)
					|| (first.getStatus() == EquivalenceStatus.NOT_EQUIVALENT
							&& swapped.getStatus() == EquivalenceStatus.EQUIVALENT);
			if (conflict) {
				violations.add(new FuzzViolation(FuzzInvariant.DETERMINISM, profile.label(), pair,
						"argument swap flipped " + first.getStatus() + " -> " + swapped.getStatus()));
			}
		} catch (Throwable t) {
			violations.add(new FuzzViolation(FuzzInvariant.ROBUSTNESS, profile.label(), pair,
					"repeat/swap check threw " + t.getClass().getSimpleName() + ": " + t.getMessage()));
		}

		if (first.getStatus() == EquivalenceStatus.EQUIVALENT && profile.runtimeRefutable()
				&& evaluable(pair, options)) {
			try {
				BoundedCounterexampleFinder.SearchResult refutation = new BoundedCounterexampleFinder(options)
						.find(pair.original(), pair.candidate());
				refutation.getCounterexample()
						.ifPresent(counterexample -> violations.add(new FuzzViolation(
								FuzzInvariant.SOUNDNESS, profile.label(), pair,
								"proved EQUIVALENT (" + first.getReason()
										+ ") but a verified witness distinguishes the trees: "
										+ counterexample.summary(),
								counterexample.getEvaluationCase())));
			} catch (Throwable t) {
				violations.add(new FuzzViolation(FuzzInvariant.ROBUSTNESS, profile.label(), pair,
						"counterexample search threw " + t.getClass().getSimpleName() + ": " + t.getMessage()));
			}
		}

		if (first.getStatus() == EquivalenceStatus.NOT_EQUIVALENT) {
			judgeWitness(pair, profile, options, first, violations);
		}
		return violations;
	}

	private void judgeWitness(TreePair pair, FuzzProfile profile, CheckOptions options, EquivalenceResult result,
			List<FuzzViolation> violations) {
		Optional<Counterexample> evidence = result.getEvidence()
				.filter(Counterexample.class::isInstance)
				.map(Counterexample.class::cast);
		if (evidence.isEmpty()) {
			violations.add(new FuzzViolation(FuzzInvariant.WITNESS_VALIDITY, profile.label(), pair,
					"NOT_EQUIVALENT without a Counterexample: " + result.getReason()));
			return;
		}
		EvaluationCase witness = evidence.get().getEvaluationCase();
		for (int run = 0; run < 2; run++) {
			try {
				Optional<EvaluationOutcome> original = evaluate(pair.original(), witness, options);
				Optional<EvaluationOutcome> candidate = evaluate(pair.candidate(), witness, options);
				if (original.isEmpty() || candidate.isEmpty()) {
					violations.add(new FuzzViolation(FuzzInvariant.WITNESS_VALIDITY, profile.label(), pair,
							"witness case '" + witness.getLabel() + "' did not evaluate to completion"));
					return;
				}
				if (original.get().sameAs(candidate.get(), profile.mode())) {
					violations.add(new FuzzViolation(FuzzInvariant.WITNESS_VALIDITY, profile.label(), pair,
							"witness case '" + witness.getLabel() + "' no longer distinguishes the trees (run "
									+ (run + 1) + ")"));
					return;
				}
			} catch (Throwable t) {
				violations.add(new FuzzViolation(FuzzInvariant.WITNESS_VALIDITY, profile.label(), pair,
						"witness replay threw " + t.getClass().getSimpleName() + ": " + t.getMessage()));
				return;
			}
		}
	}

	private boolean evaluable(TreePair pair, CheckOptions options) {
		ExpressionSafetyAnalyzer safety = new ExpressionSafetyAnalyzer(options);
		return safety.isSingleRunCounterexampleSafe(pair.original())
				&& safety.isSingleRunCounterexampleSafe(pair.candidate());
	}

	private Optional<EvaluationOutcome> evaluate(TupleExpr tree, EvaluationCase evaluationCase, CheckOptions options) {
		EvaluationAttempt attempt = new Rdf4jEvaluator().evaluate(tree, evaluationCase, options.getMaxResultRows());
		if (!attempt.isComplete()) {
			return Optional.empty();
		}
		return attempt.getOutcome();
	}
}
